import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Install & Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/getting-started.md","filePath":"en/guide/getting-started.md","lastUpdated":1783223243000}'),n={name:"en/guide/getting-started.md"};function l(r,e,s,d,h,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="install-setup" tabindex="-1">Install &amp; Setup <a class="header-anchor" href="#install-setup" aria-label="Permalink to &quot;Install &amp; Setup&quot;">​</a></h1><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>Android 9+ (API 28), <code>arm64-v8a</code></li><li>Root via Magisk, KernelSU, or APatch</li><li>F2FS <code>/data</code> partition (only for the GC feature; everything else works regardless)</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li><p>Download the latest module zip from <a href="https://github.com/Xocio/CZero/releases" target="_blank" rel="noreferrer">Releases</a>.</p></li><li><p>Flash the zip in Magisk / KernelSU / APatch.</p></li><li><p>Follow the volume-key prompts during flashing:</p><table tabindex="0"><thead><tr><th>Prompt</th><th>Action</th></tr></thead><tbody><tr><td>Choose language</td><td>Volume Up = English / Volume Down = 中文</td></tr><tr><td>Inherit old config</td><td>Volume keys to choose Y / N</td></tr></tbody></table><blockquote><p>Inheritance only carries over the black/white lists and custom path list; <code>config.json</code> is always reset to the new default.</p></blockquote></li><li><p>Reboot.</p></li><li><p>Install the <strong>CZeroX</strong> app to view status and adjust the configuration.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">First install</p><p>Not sure what to pick? Just keep the defaults — they already enable cache cleaning, background suppression, GC, and empty-folder cleanup out of the box.</p></div><h2 id="verify-it-s-working" tabindex="-1">Verify it&#39;s working <a class="header-anchor" href="#verify-it-s-working" aria-label="Permalink to &quot;Verify it&#39;s working&quot;">​</a></h2><p>After rebooting, confirm the module is running by either:</p><ul><li>Checking the CZero module description in your root manager — it should show an active state.</li><li>Opening <strong>CZeroX</strong> — the home page shows the daemon status (PID / memory) and cleaning stats.</li></ul><h2 id="updating" tabindex="-1">Updating <a class="header-anchor" href="#updating" aria-label="Permalink to &quot;Updating&quot;">​</a></h2><p>Just flash the new zip over the old install. If you choose <strong>inherit config</strong> during flashing, your black/white lists and custom path list are kept; but <code>config.json</code> always resets to the new default — re-adjust it (or reset via CZeroX) after updating if needed.</p><h2 id="uninstalling" tabindex="-1">Uninstalling <a class="header-anchor" href="#uninstalling" aria-label="Permalink to &quot;Uninstalling&quot;">​</a></h2><p>Remove the CZero module in your root manager and reboot. The module directory <code>/data/adb/modules/CZero/</code> is cleared, including its stats and logs.</p><h2 id="install-troubleshooting" tabindex="-1">Install troubleshooting <a class="header-anchor" href="#install-troubleshooting" aria-label="Permalink to &quot;Install troubleshooting&quot;">​</a></h2><ul><li><strong>Volume keys unresponsive / no key detected</strong> — on some devices <code>getevent</code> is slow; after ~60s with no input the installer defaults to Chinese and continues, so it won&#39;t hang.</li><li><strong>No effect after flashing</strong> — make sure you rebooted; then check the daemon status on the CZeroX home page and restart the process in one tap if needed.</li><li><strong>GC not working</strong> — confirm <code>/data</code> is F2FS and <code>gc.enabled</code> is <code>true</code>. Disable GC on non-F2FS devices.</li></ul><p>More in the <a href="/en/guide/faq">FAQ</a>.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/en/guide/how-it-works">How It Works</a> — the full path from boot to cleaning.</li><li><a href="/en/guide/features">Features</a> — what each feature actually does.</li><li><a href="/en/guide/configuration">Configuration</a> — every <code>config.json</code> field explained.</li><li><a href="/en/guide/schedule">Scheduling</a> — how <code>every</code> / <code>at</code> work.</li></ul>',18)])])}const p=t(n,[["render",l]]);export{g as __pageData,p as default};
